  % --- BEFORE (top section) ---
  \node[table] (P1) at (-4, 3) {Products\\(1-side)};
  \node[table] (S1) at (0, 3) {Sales\\(many-side)};
  \node[table] (R1) at (4, 3) {Regions\\(1-side)};

  % Products -> Sales (single, arrow from 1 to many)
  \draw[-{Stealth[length=6pt]}, thick, blue] (P1) -- node[above]{Single} (S1);
  % Regions -> Sales (single, arrow from 1 to many)
  \draw[-{Stealth[length=6pt]}, thick, blue] (R1) -- node[above]{Single} (S1);

  \node at (0, 1.9) {\textbf{BEFORE: Product slicer does NOT filter Regions}};

  % filter path annotation
  \draw[-{Stealth[length=5pt]}, dashed, red, thick] (P1.south) .. controls (-4,1.5) and (0,1.5) .. (S1.south);
  \node[red] at (-2, 1.3) {filter reaches Sales};
  \node[red, align=center] at (2.0, 1.3) {blocked here};
  \draw[red, thick, line width=1.5pt] (1.5, 1.6) -- (2.5, 1.0);

  % --- AFTER (bottom section) ---
  \node[table] (P2) at (-4, -1) {Products\\(1-side)};
  \node[table] (S2) at (0, -1) {Sales\\(many-side)};
  \node[table] (R2) at (4, -1) {Regions\\(1-side)};

  % Products -> Sales (single)
  \draw[-{Stealth[length=6pt]}, thick, blue] (P2) -- node[above]{Single} (S2);
  % Regions <-> Sales (both directions)
  \draw[{Stealth[length=6pt]}-{Stealth[length=6pt]}, thick, red] (R2) -- node[above]{\textbf{Both}} (S2);

  \node at (0, -2.1) {\textbf{AFTER: Product slicer NOW filters Regions}};

  % filter path annotation
  \draw[-{Stealth[length=5pt]}, dashed, green!60!black, thick] (P2.south) .. controls (-4,-3) and (0,-3) .. (S2.south);
  \draw[-{Stealth[length=5pt]}, dashed, green!60!black, thick] (S2.south) .. controls (0,-3) and (4,-3) .. (R2.south);
  \node[green!50!black] at (0, -3.5) {Products $\rightarrow$ Sales $\rightarrow$ Regions OK};

\end{tikzpicture}
